const created = $input.all();
const definitions = $('Define Role Rich Menus').all();
return created.map((item, index) => {
  const definition = definitions[index].json;
  const richMenuId = String(item.json.richMenuId || '').trim();
  if (!richMenuId) throw new Error('LINE did not return richMenuId for ' + definition.kind);
  return { json: { kind: definition.kind, richMenuId, imageUrl: definition.imageUrl } };
});
